% Figure_Placebo.m
%
% Purpose: plot the DID placebo test results
%
%
% Input: see the regression results generated by R
%

clear
close all 
clc

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% 1. PREPARE
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

% load data
data_fish   = readmatrix('dfish_permuted_coefficients.csv',"Range","B2:B1001");
data_cruise = readmatrix('dcruise_permuted_coefficients.csv',"Range","B2:B1001");
data_oper = readmatrix('operation_permuted_coefficients.csv',"Range","B2:B1001");

% mean
Mfish   = mean(data_fish);
Mcruise = mean(data_cruise);
Moper = mean(data_oper);

% baseline point estiamte
est_fish   = -2.054;
est_cruise = 1.881;
est_oper = -0.173;

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% 2. PLOT
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

xAux  = linspace(-0.53,0.53,30);
xAux2 = linspace(-0.018,0.018,30);

xFish   = [est_fish est_fish];
xCruise = [est_cruise est_cruise];
xoper = [est_oper est_oper];
xFish2   = [Mfish Mfish];
xCruise2 = [Mcruise Mcruise];
xoper2 = [Moper Moper];

yAux  = [0 352];

figure
subplot(3,1,1)
histogram(data_oper,xAux)
hold 
plot(xoper2,yAux,...
    'Color','k',...
    'LineWidth',2,...
    'LineStyle',':')
plot(xoper,yAux,...
    'Color',[1,0,0],...
    'LineWidth',2,...
    'LineStyle',':')
title('(a) Operation hours',...
    'Fontname', 'arial','FontSize',16.,...
    'Interpreter', 'latex')
ylabel({'Frequency'},...
    'Fontname', 'arial','FontSize',16,...
    'Interpreter', 'latex')
xlim([-2.4,2.4])
ylim([0,352])
set(gca,'XTick',[-2,-1.5,-1,-.5,0,.5,1,1.5,2],...
        'YTick',[0,100,200,300],...
        'XTickLabel',{'-2.0';'-1.5';'-1.0';'-0.5';'0';'0.5';'1.0';'1.5';'2.0'},...
        'Fontname', 'times new roman','FontSize',12,...
        'box','off')

yAux  = [0 122];
subplot(3,1,2)
histogram(data_fish,xAux)
hold 
plot(xFish2,yAux,...
    'Color','k',...
    'LineWidth',2,...
    'LineStyle',':')
plot(xFish,yAux,...
    'Color',[1,0,0],...
    'LineWidth',2,...
    'LineStyle',':')
title('(b) Fishing hours',...
    'Fontname', 'arial','FontSize',16.,...
    'Interpreter', 'latex')
ylabel({'Frequency'},...
    'Fontname', 'arial','FontSize',16,...
    'Interpreter', 'latex')
xlim([-2.4,2.4])
ylim([0,122])
set(gca,'XTick',[-2,-1.5,-1,-.5,0,.5,1,1.5,2],...
        'YTick',[0,40,80,120],...
        'XTickLabel',{'-2.0';'-1.5';'-1.0';'-0.5';'0';'0.5';'1.0';'1.5';'2.0'},...
        'Fontname', 'times new roman','FontSize',12,...
        'box','off')

subplot(3,1,3)
histogram(data_cruise,xAux)
hold 
plot(xCruise2,yAux,...
    'Color','k',...
    'LineWidth',2,...
    'LineStyle',':')
plot(xCruise,yAux,...
    'Color',[1,0,0],...
    'LineWidth',2,...
    'LineStyle',':')

title('(c) Non-fishing hours',...
    'Fontname', 'arial','FontSize',16.,...
    'Interpreter', 'latex')
ylabel({'Frequency'},...
    'Fontname', 'arial','FontSize',16,...
    'Interpreter', 'latex')
xlabel({'Coefficients from placebo regressions'},...
    'Fontname', 'arial','FontSize',16,...
    'Interpreter', 'latex')
xlim([-2.4,2.4])
ylim([0,122])
set(gca,'XTick',[-2,-1.5,-1,-.5,0,.5,1,1.5,2],...
        'YTick',[0,40,80,120],...
        'XTickLabel',{'-2.0';'-1.5';'-1.0';'-0.5';'0';'0.5';'1.0';'1.5';'2.0'},...
        'Fontname', 'times new roman','FontSize',12,...
        'box','off')



